questions.question:
Predict the output of the following program and explain the order of constructor/destructor calls:

#include <iostream>
using namespace std;

class A {
public:
 A() { cout << "A constructed\n"; }
 ~A() { cout << "A destroyed\n"; }
};

class B : public A {
public:
 B() { cout << "B constructed\n"; }
 ~B() { cout << "B destroyed\n"; }
};

class C : public B {
public:
 C() { cout << "C constructed\n"; }
 ~C() { cout << "C destroyed\n"; }
};

int main() {
 C obj;
 return 0;
}
